// Time:  O(n)
// Space: O(1)

class Solution {
public:
    int minimumDeletions(vector<int>& nums) {
        int i = min_element(cbegin(nums), cend(nums)) - cbegin(nums);
        int j = max_element(cbegin(nums), cend(nums)) - cbegin(nums);
        if (i > j) {
            swap(i, j);
        }
        return min({(i + 1) + (static_cast<int>(size(nums) - j)), j + 1, static_cast<int>(size(nums)) - i}); 
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def minimumDeletions(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        i, j = nums.index(min(nums)), nums.index(max(nums))
        if i > j:
            i, j = j, i
        return min((i+1)+(len(nums)-j), j+1, len(nums)-i)
